mapper.insert:
/* jaram.common.mapper.CommonMapper.insertEditorMessage */
INSERT INTO EDT_MSG_INFO
(
      SEQ
    , EDT_ID
    , EDT_TEXT
    , EDT_TITLE
    , EDT_SUB_TITLE
    , PAGE
    , MAIN_IMG_PATH
    , QNA_PASSWORD
    , QNA_SECURE_YN
    , INPUT_DT
    , INPUT_ID
    , INPUT_NAME
    , UPDATE_DT
    , UPDATE_ID
    , UPDATE_NAME
)
VALUE
(
      #{SEQ}
    , #{EDT_ID}
    , #{EDT_TEXT}
    , #{EDT_TITLE}
    , #{EDT_SUB_TITLE}
    , #{PAGE}
    , #{MAIN_IMG_PATH}
    , #{QNA_PASSWORD}
    , IFNULL(#{QNA_SECURE_YN}, 'N')
    , IFNULL(#{INPUT_DT}, NOW())
    , #{INPUT_ID}
    , #{INPUT_NAME}
    , NOW()
    , #{UPDATE_ID}
    , #{UPDATE_NAME}
    )
ON DUPLICATE KEY UPDATE
     EDT_TITLE     = #{EDT_TITLE}
   , EDT_SUB_TITLE = #{EDT_SUB_TITLE}
   , EDT_TEXT      = #{EDT_TEXT}
   , MAIN_IMG_PATH = #{MAIN_IMG_PATH}
   , QNA_SECURE_YN = IFNULL(#{QNA_SECURE_YN}, 'N')
   , UPDATE_DT     = NOW()
   , UPDATE_ID     = #{INPUT_ID}

mapper.delete:
/* jaram.common.mapper.CommonMapper.deleteEditorMessage [editor message 삭제] */
UPDATE  EDT_MSG_INFO
SET     DEL_YN = 'Y'
WHERE   SEQ = #{SEQ}
AND     PAGE = #{PAGE}

mapper.select:
/* jaram.common.mapper.CommonMapper.selectEditorMessage */ SELECT SEQ , EDT_ID , EDT_TITLE , EDT_SUB_TITLE , EDT_TEXT , PAGE , MAIN_IMG_PATH , QNA_PASSWORD , QNA_SECURE_YN , VIEW_CNT , CASE WHEN TIMESTAMPDIFF(MINUTE , UPDATE_DT, NOW()) < 1440 THEN CASE WHEN TIMESTAMPDIFF(MINUTE , UPDATE_DT, NOW()) < 60 THEN CONCAT( TIMESTAMPDIFF(MINUTE , UPDATE_DT, NOW()) , '분 전') ELSE CONCAT( TIMESTAMPDIFF(HOUR , UPDATE_DT, NOW()) , '시간 전') END ELSE DATE_FORMAT(UPDATE_DT, '%Y-%m-%d') END AS INPUT_DT , INPUT_ID , INPUT_NAME , NOW_SESSION FROM EDT_MSG_INFO WHERE PAGE = #{PAGE}
AND SEQ = #{SEQ}
AND SEQ = ( SELECT MAX(SEQ) FROM EDT_MSG_INFO WHERE PAGE = #{PAGE} )
AND DEL_YN != 'Y'

/* jaram.common.mapper.CommonMapper.selectEditorMessageList [editor message list 조회]*/ SELECT @ROWNUM:=@ROWNUM+1 AS RN , SEQ , EDT_ID , EDT_TITLE , EDT_SUB_TITLE , EDT_TEXT , PAGE , MAIN_IMG_PATH , QNA_PASSWORD , QNA_SECURE_YN , VIEW_CNT , CASE WHEN TIMESTAMPDIFF(MINUTE , UPDATE_DT, NOW()) < 1440 THEN CASE WHEN TIMESTAMPDIFF(MINUTE , UPDATE_DT, NOW()) < 60 THEN CONCAT( TIMESTAMPDIFF(MINUTE , UPDATE_DT, NOW()) , '분 전') ELSE CONCAT( TIMESTAMPDIFF(HOUR , UPDATE_DT, NOW()) , '시간 전') END ELSE DATE_FORMAT(UPDATE_DT, '%Y-%m-%d') END AS INPUT_DT , INPUT_ID , INPUT_NAME , (SELECT COUNT(*) FROM BOARD_COMMENT S1 WHERE S1.EDT_SEQ = SEQ AND S1.DEL_YN != 'Y') AS COMMENT_CNT , (SELECT COUNT(*) FROM FILE_INFO S2 WHERE S2.EDT_SEQ = T1.SEQ) AS FILE_CNT , QNA_SECURE_YN FROM EDT_MSG_INFO T1 WHERE PAGE = #{PAGE} AND DEL_YN != 'Y' AND (@ROWNUM:=0) = 0
AND EDT_TITLE LIKE CONCAT('%', #{SEARCH_TITLE} , '%')
ORDER BY UPDATE_DT DESC, INPUT_DT DESC

mapper.insert:
/* jaram.common.mapper.CommonMapper.insertFileInfo [file 저장] */
INSERT INTO FILE_INFO
(
      EDT_SEQ
    , COMMENT_SEQ
    , ORG_FILE_NAME
    , SAVE_FILE_NAME
    , FILE_SIZE
    , INPUT_DT
    , INPUT_ID
)
VALUE
(
      #{EDT_SEQ}
    , #{COMMENT_SEQ}
    , #{ORG_FILE_NAME}
    , #{SAVE_FILE_NAME}
    , #{FILE_SIZE}
    , NOW()
    , #{INPUT_ID}
)

mapper.delete:
/* jaram.common.mapper.CommonMapper.deleteFileInfo [file 삭제] */
DELETE  FROM FILE_INFO
WHERE   SEQ = #{FILE_SEQ}

